# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

def update_account_balances(transactions, accounts):
    """
    Processes a list of financial transactions and updates the account balances.

    :param transactions: List of dictionaries, where each dictionary represents a transaction.
                         Each transaction should have keys 'account_id' (string), 'amount' (float),
                         and 'type' ('credit' or 'debit').
    :param accounts: Dictionary where keys are account IDs (strings) and values are current balances (floats).
    :return: Updated dictionary of account balances.
    """
    for transaction in transactions:
        account_id = transaction['account_id']
        amount = transaction['amount']
        trans_type = transaction['type']

        if account_id in accounts:
            if trans_type == 'credit':
                accounts[account_id] += amount
            elif trans_type == 'debit':
                accounts[account_id] -= amount
        else:
            print(f"Account ID {account_id} not found.")

    return accounts

# Example usage:
transactions = [
    {'account_id': '123', 'amount': 100.0, 'type': 'credit'},
    {'account_id': '456', 'amount': 200.0, 'type': 'debit'},
    {'account_id': '789', 'amount': 50.0, 'type': 'credit'}
]

accounts = {
    '123': 1000.0,
    '456': 1500.0
}

updated_accounts = update_account_balances(transactions, accounts)
print(updated_accounts)